UPDATE advisor_content
SET content = '<h1 style="font-size: 32px; font-weight: 700; color: #000000; margin: 0 0 24px 0; line-height: 1.3;">December 10, 2025</h1>

<div style="border: 2px solid #cbd5e1; border-radius: 12px; padding: 20px 24px; margin: 0 0 32px 0; background-color: #f8fafc;">
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">"Like snowflakes, every agent brings something unique, and together we create something powerful."<br>— MPB Health</p>
</div>

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Updates:</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">App Benefits Start Date:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Please advise your new Members that even though they are able to download the app upon enrollment, some of the services and benefits will <strong style="color: #111827;">NOT be available until their Start date</strong> (ID Cards, RX Valet, Virtual Care/Telehealth).</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Updated Member Forms:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">There are 2 Cognito Forms that have been archived since they are outdated:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">MPowering Benefits Existing Member Payment Update</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">MPowering Benefits Existing Member Change Form</li>
</ul>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">The new forms are:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://mpb.health/membership-changes/" style="color: #2563eb; text-decoration: underline;">Member Updates</a></li>
</ul>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">These forms are available on the MPB Health website &amp; in the Advisor Playbook.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Booking Virtual Care Appointments on the MPB Health App:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">When booking consultations for Primary Care, Psychology and Psychiatry, members can choose several days/times to reduce having to go back and forth with the doctor. The new system was rolled out to all members <strong style="color: #111827;">Monday, December 8</strong>.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">PHCS – Nominating Providers to the Network:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Keep in mind, even though there is a process to nominate a provider into PHCS network, it is up to the provider and the practice to join a network. This process usually takes between <strong style="color: #111827;">90 to 120 days</strong>.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Groups – Employee Changes:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">All change requests for members on List Bills need to come through the Employer. If an employee on a List Bill contacts you directly to make changes, please refer them back to their employer to initiate the request.</p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Reminders:</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Secure HSA, Care+ and Direct Price Increase:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">The updated 2026 pricing has been changed on the enrollment platform, in e123 and in marketing materials. Please view the changes and ensure you''re sharing the most current information.</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">The minimum IUA will increase from <strong style="color: #111827;">$1000 to $1250</strong> for New and Existing enrollments.</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">New Rates:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/care.pdf" style="color: #2563eb; text-decoration: underline;">Care+ Price Sheet</a></li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/Direct.pdf" style="color: #2563eb; text-decoration: underline;">Direct Price Sheet</a></li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/securehsa.pdf" style="color: #2563eb; text-decoration: underline;">Secure HSA Price Sheet</a></li>
</ul>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Enrollment Deadline</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">The enrollment deadline is <strong style="color: #111827;">12am EST on the 20th</strong> of every month for a 1st of the following month effective date.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">MPB Health App</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Please continue to encourage your members to download the MPB Health App!!</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://mpb.health/download-app" style="display: inline-block; padding: 12px 28px; background-color: #2563eb; color: #ffffff; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">MPB Health App Download</a></p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Rewards in Motion</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">MGM Grand Las Vegas!</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Open Enrollment is almost here, are you going to LAS VEGAS!? Let us know how we can support you!</p>'
WHERE slug = 'advisor-bulletin-december-10-2025' AND content_type = 'bulletin';
