-- ARTICLE 3: advisor-bulletin-november-26-2025
-- ============================================================
UPDATE advisor_content
SET content = '<h1 style="font-size: 32px; font-weight: 700; color: #000000; margin: 0 0 24px 0; line-height: 1.3;">November 26, 2025</h1>

<div style="border: 2px solid #cbd5e1; border-radius: 12px; padding: 20px 24px; margin: 0 0 32px 0; background-color: #f8fafc;">
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">"Gratitude is not only the greatest of virtues, but the parent of all the others."<br>— Cicero</p>
</div>

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Reminders</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Freedom to Share Act:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Ohio has taken an important first step toward expanding healthcare freedom and flexibility. The Freedom to Share Act has passed the Ohio House and is now moving to the Senate for consideration, great news for those who value medical cost-sharing options and greater choice in how they manage and pay for their healthcare.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">PHCS Network in Michigan – Limitations:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">We have been informed by ARM Ltd. that there is a small region in Michigan without adequate network coverage with PHCS. We will be notifying Members in Michigan to contact <strong style="color: #111827;">MPB Concierge</strong> for a solution to their Preventive Screening needs before any procedure.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Secure HSA, Care+ and Direct Price Increase:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">The updated 2026 pricing has been changed on the enrollment platform, in e123 and in marketing materials. The minimum IUA will increase from <strong style="color: #111827;">$1000 to $1250</strong> for New and Existing enrollments.</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/care.pdf" style="color: #2563eb; text-decoration: underline;">Care+ Price Sheet</a></li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/Direct.pdf" style="color: #2563eb; text-decoration: underline;">Direct Price Sheet</a></li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/securehsa.pdf" style="color: #2563eb; text-decoration: underline;">Secure HSA Price Sheet</a></li>
</ul>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Pre-Existing Conditions (See Sharing Guidelines)</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">If a member has been examined, diagnosed, treated, had symptoms, taken medication, or has an increased risk for a condition, it qualifies as a pre-existing and there will be <strong style="color: #111827;">no sharing in the first year</strong>.</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Pre-ex sharing limits:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><strong style="color: #111827;">Year 4 and beyond:</strong> Up to $125,000</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><strong style="color: #111827;">Year 3:</strong> Up to $50,000</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><strong style="color: #111827;">Year 2:</strong> Up to $25,000</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><strong style="color: #111827;">Year 1:</strong> No sharing</li>
</ul>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Tobacco Use (See Sharing Guidelines)</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Members who use tobacco will incur a surcharge of between <strong style="color: #111827;">$50–$75 per month</strong>. Additionally, members over 50 who use tobacco will have reduced sharing benefits for major conditions.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Maternity (See Sharing Guidelines)</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Secure HSA, Care+, and Direct Plans:</strong> 6 month waiting period from Enrollment for conception.</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Premium Care &amp; Premium HSA:</strong> Delivery date must be at least nine months after enrollment.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Needs After Enrollment and Prior to Effective Date:</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Sedera (Premium Care &amp; Premium HSA):</strong> Any medical costs incurred after the enrollment date but prior to the start date are <strong style="color: #111827;">NOT shareable</strong>.</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">It''s only new medical conditions that occur after enrollment and prior to start date that would not be considered pre-ex after start date.</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">If the ER visit pertains to an existing pre-ex, it will remain a pre-ex after the start date.</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Any dates of service prior to the start date are not shareable.</li>
<li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">If the event involves a new medical condition, that condition will not be treated as a pre-existing condition after the start date.</li>
</ul>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Membership Changes</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">We are expecting a higher volume of membership changes during Open Enrollment season. Please have your members fill out the <strong style="color: #111827;">"Change Membership"</strong> section, specifying the membership they wish to switch to and their current membership name.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">MPB Health App</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Please encourage your members to download the MPB Health App!!</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://mpb.health/download-mpbhealth-app/" style="display: inline-block; padding: 12px 28px; background-color: #2563eb; color: #ffffff; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">MPB Health App Download</a></p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Rewards in Motion</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">MGM Grand Las Vegas!</h2>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Open Enrollment is almost here, are you going to LAS VEGAS!?</p>'
WHERE slug = 'advisor-bulletin-november-26-2025' AND content_type = 'bulletin';
