UPDATE advisor_content
SET content = '
<h1 style="font-size: 32px; font-weight: 700; color: #000000; margin: 0 0 24px 0; line-height: 1.3;">October 1st Half</h1>

<div style="border: 2px solid #cbd5e1; border-radius: 12px; padding: 20px 24px; margin: 0 0 32px 0; background-color: #f8fafc;">
  <p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 8px 0;"><em>"If you are not taking care of your customer, your competitor will."</em></p>
  <p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0;">— <em>Bob Hooey</em></p>
</div>

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Updates</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Sedera Changes in Florida</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Sedera and their legal counsel have advised that, due to Florida Statute § 624.1265, they will be unable to pay commissions on any new Florida business written after July 1, 2025. However, they will continue to pay commissions on business written prior to that date.</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">As a result, MPB Health has designated Florida as a no-sell state for Sedera plans (Premium Care and Premium HSA).</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/09/No-Sell-States-Chart-9.pdf" style="color: #2563eb; text-decoration: underline;">No Sell States Chart</a></p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Zion Sharing Request Payments</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Typical end-to-end processing time is about 60 days, depending on:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Time required to obtain medical records (if needed)</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">How promptly the member uploads documents</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">How quickly the provider submits bills</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Appeals of declined sharing decisions have no fixed timeline</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Zion can process needs in as little as 2 weeks, however, times may vary</li>
</ul>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Pet Telehealth Disclaimer</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">This service is not for medical emergencies or urgent situations. This service should not be considered veterinary care, and is not a substitute for professional veterinary care, diagnosis, treatment or prescription for your pet.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Zion HealthShare Membership &amp; IUA Updates – Member Communications Schedule</h2>

<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">October 27, 2025 — Email</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">November 11, 2025 — Newsletter</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">December 1, 2025 — Email &amp; Mailed notices to follow</li>
</ul>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Price sheets:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/care.pdf" style="color: #2563eb; text-decoration: underline;">Care+ Price Sheet</a></li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/Direct.pdf" style="color: #2563eb; text-decoration: underline;">Direct Price Sheet</a></li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/securehsa.pdf" style="color: #2563eb; text-decoration: underline;">Secure HSA Price Sheet</a></li>
</ul>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;" />

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Alternative and Functional Guidelines</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Zion HealthShare – Therapeutic Treatments</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">When prescribed and performed by a licensed medical professional for a specific illness, injury, or disease, expenses for therapeutic treatments are eligible for sharing up to a maximum of $7,500 or 35 treatments per medical need. Therapeutic services include:</p>
<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Physical therapy</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Massage therapy</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Chiropractic treatments</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Alternative therapies such as acupuncture, craniosacral therapy, dry needling, ozone treatments, prolotherapy</li>
</ul>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Sedera – Alternative Practices</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Unproven and insufficiently proven diagnostics and therapeutics are considered Alternative and are not Shareable. Alternative practice methods include ayurvedic, acupuncture, homeopathy, naturopathy, functional/integrative medicine, most use of CBD and all marijuana.</p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;" />

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Reminders</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Enrollment Reminders</h2>

<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">When enrolling a 26+ or new spouse/dependent, you must use a unique email and phone number.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">When entering an EIN or Social Security Number for MEC/HSA plans, NO DASHES please.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Enrollments are due by 12 midnight on the 20th of the month.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Milestone Birthdays Increases – Members who age up to new age bands will have an increase for January 1, 2026.</li>
</ul>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;" />

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Rewards in Motion</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">MGM Grand Las Vegas Contest</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://advisor.mpb.health/zion-healthshare-contest/" style="display: inline-block; padding: 12px 28px; background-color: #2563eb; color: #ffffff; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">Leaderboard</a></p>
'
