-- ARTICLE 8: important-update-regarding-price-increase-2026
-- (Letter-style)
-- ============================================================
UPDATE advisor_content
SET content = '
<h1 style="font-size: 32px; font-weight: 700; color: #000000; margin: 0 0 24px 0; line-height: 1.3;">Pricing &amp; IUA updates and how to position it.</h1>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Dear MPB Health Advisors,</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Care+, Secure HSA, and Direct will see modest price updates designed to maintain robust sharing for major needs and keep monthly amounts low as healthcare costs continue to rise.</p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Key updates and timing</h3>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Dec 20, 2025 (Billing):</strong> A modest monthly increase applies to Care+, Direct, and Secure HSA memberships.</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Jan 1, 2026 (IUA):</strong> Only members currently at a $1,000 IUA will update to $1,250 per medical Need. All other IUA levels are unchanged.</p>

<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/2026-prices-Care-Direct-Secure-HSA-2.pdf" style="color: #2563eb; text-decoration: underline;">Price sheets</a></li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/10/2026-prices-Care-Direct-Secure-HSA-Comparison-4.pdf" style="color: #2563eb; text-decoration: underline;">Comparison sheet</a></li>
</ul>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Positive positioning</h3>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">"These minor updates strengthen the community''s ability to share larger medical needs while keeping your monthly amount highly competitive."</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">"The IUA change affects only those at $1,000; if your IUA is different, you''re not impacted."</p>
<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">"Remember, the IUA only applies when you have a shareable Need. Once met, eligible expenses are shared by the community."</p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Reminders</h3>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">When prospecting, remind clients to take advantage of the lower membership rates they receive until Dec 20th. Don''t forget to remind your clients to download the new MPB Health app for easier access.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Our memberships remain competitive in price and deliver significant savings versus traditional options. Keep prospecting, keep educating, and keep offering side-by-side comparisons. When clients see the numbers, we win on value.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Your Expertise + Our Value = Wins</strong></p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Reba Larney</strong><br>Business Development Director<br>(561) 922 9647<br>Rebalarney@mympb.com</p>
'
WHERE slug = 'important-update-regarding-price-increase-2026' AND content_type = 'bulletin';
-- ============================================================
-- ARTICLE 9: important-update-regarding-sedera-plans-in-florida
-- (Letter-style)
-- ============================================================
UPDATE advisor_content
SET content = '
<h1 style="font-size: 32px; font-weight: 700; color: #000000; margin: 0 0 24px 0; line-height: 1.3;">Important Update Regarding Sedera Plans in Florida</h1>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Dear MPB Health Advisors,</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">We wanted to inform you of an important update regarding Sedera and the recent legislative changes in Florida.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Sedera and their legal counsel have advised that, due to Florida Statute § 624.1265 concerning Religious Health Care Sharing Ministries, they will be unable to pay commissions on any new Florida business written after July 1, 2025. However, they will continue to pay commissions on business written prior to that date.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">As a result of this development—and due to the fact that Sedera plans can no longer be sold by licensed health agents in Florida—MPB Health has designated Florida as a no-sell state for Sedera plans (Premium Care and Premium HSA).</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">We want to emphasize that this change does not affect other plans offered by MPB Health. Click to view our updated Do Not Sell States &amp; Individual Mandates chart.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://advisor.mpb.health/wp-content/uploads/2025/02/No-Sell-States-Chart3.png" style="color: #2563eb; text-decoration: underline;">NO SELL STATES</a></p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Thank you for your attention to this matter and your continued partnership.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Regards,</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><strong style="color: #111827;">Reba Larney</strong><br>Business Development Director<br>(561) 922 9647<br>Rebalarney@mympb.com</p>
'
WHERE slug = 'important-update-regarding-sedera-plans-in-florida' AND content_type = 'bulletin';
