-- ARTICLE 10: advisor-bulletin-september-24-2025
-- (Regular bulletin with blockquote, Updates/Reminders sections)
-- ============================================================
UPDATE advisor_content
SET content = '
<h1 style="font-size: 32px; font-weight: 700; color: #000000; margin: 0 0 24px 0; line-height: 1.3;">September 2nd Half</h1>

<div style="border: 2px solid #cbd5e1; border-radius: 12px; padding: 20px 24px; margin: 0 0 32px 0; background-color: #f8fafc;">
  <p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 8px 0;"><em>"Sell the problem you solve, not the product."</em></p>
  <p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0;">— <em>Unknown</em></p>
</div>

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Updates</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Sedera in Florida</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Florida has a new statute stating that Florida-licensed agents cannot sell religious Health Care Sharing Ministry plans (HCSMs). In light of this, Sedera may discontinue commissions on plans sold by a licensed FL agent to members in Florida. We do not have all the details yet, but expect those by next week. We will send a dedicated bulletin when we have the final decision from the Sedera legal team.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">New Landing Pages Coming Soon!</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">We are optimizing the Advisor Landing Page and, once we have completed a peer review, we will have a training regarding this exciting update on the October 14 Advisor call.</p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Virtual Behavioral Health</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">MPB Health''s virtual behavioral health services are delivered through a national Employee Assistance Program (EAP) partner. After logging into the app, members are prompted to call 1-833-483-0831 to speak with an intake clinician, who will assess the situation and authorize an initial course of care—typically six sessions. Within 24 hours, members receive a list of available local practitioners along with appointment times.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">The number of sessions may be extended at the provider''s discretion based on the member''s clinical needs. Providers may also recommend ongoing care with a psychologist to support optimal treatment and outcomes.</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">There is no annual limit on clinically appropriate utilization of behavioral health.</p>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Reminders</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Enrollments</h2>

<ul style="margin: 0 0 16px 0; padding-left: 24px; list-style-type: disc;">
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">When using the 100MPOWER code to waive the enrollment fee, the member must enter the code then click the Plus (+) sign to activate it.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">When there is a Spouse or Dependent being entered on the 1st screen of the enrollment, use the Pencil on the second screen to enter the remaining information for the dependent.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">When enrolling a MEC plan member, do not use dashes when filling out the EIN/SSN number box.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Enrollments are due by 12 midnight on the 20th of the month. This is a firm deadline.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">MEC/HSA Enrollments require that the Member be a Sole Proprietor and have a Social Security Number or EIN or be a 1099 Contractor.</li>
  <li style="font-size: 16px; line-height: 1.7; color: #334155; margin-bottom: 6px;">Dependent members who get married must have their own membership and can no longer be on their parents'' plan.</li>
</ul>

<hr style="border: none; border-top: 2px solid #e2e8f0; margin: 40px 0;">

<h3 style="text-align: center; font-size: 22px; font-weight: 700; color: #000000; margin: 40px 0 24px 0; padding-bottom: 12px; border-bottom: 2px solid #e2e8f0;">Rewards in Motion</h3>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">MGM Grand Las Vegas Contest</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://advisor.mpb.health/zion-healthshare-contest/" style="display: inline-block; padding: 12px 28px; background-color: #2563eb; color: #ffffff; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">Leaderboard</a></p>

<h2 style="font-size: 24px; font-weight: 700; color: #000000; margin: 32px 0 16px 0; line-height: 1.3;">Google Reviews</h2>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;">Receive 5 or more Google reviews from members &amp; get dinner on us!</p>

<p style="font-size: 16px; line-height: 1.7; color: #334155; margin: 0 0 12px 0;"><a href="https://mpb.health/review-us/" style="display: inline-block; padding: 12px 28px; background-color: #2563eb; color: #ffffff; border-radius: 8px; text-decoration: none; font-weight: 600; font-size: 16px;">Review Us</a></p>
'
WHERE slug = 'advisor-bulletin-september-24-2025' AND content_type = 'bulletin';
